from source import bitcount
import concurrent.futures


def test_bitcount_does_not_infinite_loop_and_returns_correct_value():
    """Ensure bitcount returns the correct count and terminates."""
    def run_with_timeout(func, *args, timeout=0.1):
        with concurrent.futures.ThreadPoolExecutor(max_workers=1) as executor:
            future = executor.submit(func, *args)
            try:
                return future.result(timeout=timeout)
            except concurrent.futures.TimeoutError:
                raise AssertionError("bitcount did not terminate (possible infinite loop)")

    result = run_with_timeout(bitcount, 127, timeout=0.1)
    assert result == 7, f"Expected bitcount(127) to be 7, got {result}"
